const decision = $node["Parse Claude Response"].json || {};
const advisoryResp = $json || {};
const advisory = advisoryResp.advisory || {};

const tailRisk = Number(advisory.tail_risk_score ?? 0.5);
const scenarioBias = String(advisory.scenario_bias || "neutral").toLowerCase();
const confidence = Number(decision.confidence ?? 0);

const thresholds = {
  tail_risk_block: 0.7,
  risk_off_min_confidence: 8
};

let allowTrade = true;
let reason = "MiroFish gate passed";

if (tailRisk >= thresholds.tail_risk_block) {
  allowTrade = false;
  reason = `Blocked: tail_risk_score ${tailRisk.toFixed(2)} >= ${thresholds.tail_risk_block}`;
}

if (allowTrade && scenarioBias === "risk_off" && confidence < thresholds.risk_off_min_confidence) {
  allowTrade = false;
  reason = `Blocked: scenario_bias=risk_off requires confidence >= ${thresholds.risk_off_min_confidence} (got ${confidence})`;
}

if (advisoryResp.degraded === true) {
  reason = `${reason} | advisory_degraded=true (fail-open active)`;
}

return {
  json: {
    ...advisoryResp,
    advisory_gate: {
      allow_trade: allowTrade,
      reason,
      thresholds,
      evaluated_at: new Date().toISOString()
    }
  }
};

